const SECRET_TOKEN = '<TELEGRAM_WEBHOOK_SECRET_TOKEN>';
const HMAC_SECRET = '<N8N_WEBHOOK_SECRET>';

const item = $input.first().json;
const headers = item.headers || {};
if ((headers['x-telegram-bot-api-secret-token'] || '') !== SECRET_TOKEN) {
  return [];
}
const text = item.body && item.body.message && item.body.message.text;
if (!text || typeof text !== 'string') {
  return [];
}
const payload = JSON.stringify({ source: 'telegram', text: text.slice(0, 4000) });

let signature;
try {
  const c = require('crypto');
  signature = c.createHmac('sha256', HMAC_SECRET).update(payload).digest('hex');
} catch (e) {
  const enc = new TextEncoder();
  const key = await crypto.subtle.importKey('raw', enc.encode(HMAC_SECRET), { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  const sig = await crypto.subtle.sign('HMAC', key, enc.encode(payload));
  signature = Array.from(new Uint8Array(sig)).map(b => b.toString(16).padStart(2, '0')).join('');
}
return [{ json: { payload, signature } }];
